"use client";

import React, { useState } from "react";

export default function Dashboard() {
  const [loading, setLoading] = useState(false);
  const [showResults, setShowResults] = useState(false);

  const handleRunAudit = () => {
    setLoading(true);
    setShowResults(false);

    setTimeout(() => {
      setLoading(false);
      setShowResults(true);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-gray-950 text-white p-6">
      <h1 className="text-3xl font-bold mb-6">Security Audit Dashboard</h1>

      {/* Run Audit Button */}
      <div className="flex justify-center mb-10">
        <button
          onClick={handleRunAudit}
          className="px-8 py-4 bg-purple-600 hover:bg-purple-700 rounded-2xl text-lg font-semibold shadow-lg transition"
        >
          {loading ? "Running Audit..." : "Run Audit"}
        </button>
      </div>

      {/* Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        <div className="bg-gray-900 p-6 rounded-2xl shadow">
          <p className="text-gray-400">Before Score</p>
          <h2 className="text-2xl font-bold">45%</h2>
        </div>
        <div className="bg-gray-900 p-6 rounded-2xl shadow">
          <p className="text-gray-400">After Score</p>
          <h2 className="text-2xl font-bold">92%</h2>
        </div>
        <div className="bg-gray-900 p-6 rounded-2xl shadow">
          <p className="text-gray-400">Time Saved</p>
          <h2 className="text-2xl font-bold">3 hrs</h2>
        </div>
        <div className="bg-gray-900 p-6 rounded-2xl shadow">
          <p className="text-gray-400">Cost Saved</p>
          <h2 className="text-2xl font-bold">$1200</h2>
        </div>
      </div>

      {/* Results Table */}
      {showResults && (
        <div className="bg-gray-900 rounded-2xl shadow overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-gray-800">
              <tr>
                <th className="p-4">File</th>
                <th className="p-4">Issue</th>
                <th className="p-4">Severity</th>
                <th className="p-4">PR Fix</th>
              </tr>
            </thead>
            <tbody>
              <tr className="border-t border-gray-800">
                <td className="p-4">auth.js</td>
                <td className="p-4">SQL Injection</td>
                <td className="p-4 text-red-400">High</td>
                <td className="p-4 text-green-400">Generated</td>
              </tr>
              <tr className="border-t border-gray-800">
                <td className="p-4">config.js</td>
                <td className="p-4">API Key Leak</td>
                <td className="p-4 text-yellow-400">Medium</td>
                <td className="p-4 text-green-400">Generated</td>
              </tr>
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
